franconian_cities = {
    "Bavaria": ["Nuremberg", "Würzburg", "Bamberg", "Bayreuth", "Ansbach", "Coburg"],
    "Thuringia": ["Suhl", "Meiningen"],
    "Baden-Württemberg": ["Schwäbisch Hall"]
}

def is_in_franconia(city):
    for region, cities in franconian_cities.items():
        if city in cities:
            return True
    return False

# Example usage:
print(is_in_franconia("Bamberg"))  # Output: True
print(is_in_franconia("Berlin"))   # Output: False
